public static class TpmStructuresTests
{
    // The "magic" field in TPMS_ATTEST must equal TPM_GENERATED_VALUE (0xff544347, "ÿTCG")
    // to prove the structure was generated by a genuine TPM.
    // See TPM 2.0 Part 2, section 6.2 (TPM_GENERATED_VALUE).
    private const uint InvalidTpmGeneratedMagic = 0x12345678;

    // TPMS_ATTEST.type identifies the attestation statement kind (e.g., ST_ATTEST_CERTIFY = 0x8017).
    // See TPM 2.0 Part 2, section 10.12.8 (TPMS_ATTEST) and section 6.9 (TPMI_ST_ATTEST).
    private const ushort InvalidAttestationStatementType = 0x9999;

    // TPMT_PUBLIC.type and TPMT_SIGNATURE.sigAlg identify the algorithm (RSA, ECC, etc.).
    // See TPM 2.0 Part 2, section 12.2.4 (TPMT_PUBLIC) and section 11.3.4 (TPMT_SIGNATURE).
    private const ushort UnsupportedAlgorithmId = 0x9999;

    // TPM object attributes are bit flags describing key usage policies (sign, decrypt, fixedTPM, etc.).
    // See TPM 2.0 Part 2, section 8.3 (TPMA_OBJECT).
    private const uint TestObjectAttributes = 0x11223344;
    private const uint AlternateTestObjectAttributes = 0x55667788;

    private const ushort TestRsaKeyBits = 2048;
    private const uint TestRsaExponent = 65537;

    // KDF scheme for ECC parameters. 0x0000 is not a valid algorithm ID but is used here
    // as a null/no-op KDF. See TPM 2.0 Part 2, section 11.2.5 (TPMS_ECC_PARMS).
    private const ushort NullKdf = 0x0000;

    // "Don't care" values used when a test only exercises one specific field and the
    // remaining TPMS_CLOCK_INFO / firmware fields are irrelevant to the assertion.
    // See TPM 2.0 Part 2, section 10.11.1 (TPMS_CLOCK_INFO) and 10.12.8 (TPMS_ATTEST).
    private const ulong FillerClock = 1UL;
    private const uint FillerResetCount = 2U;
    private const uint FillerRestartCount = 3U;
    private const byte FillerSafe = 4;
    private const ulong FillerFirmwareVersion = 5UL;

    private const ulong TestClock = 100UL;
    private const uint TestResetCount = 200U;
    private const uint TestRestartCount = 300U;
    private const byte TestSafe = 1;
    private const ulong TestFirmwareVersion = 500UL;
    private const byte TrailingByte = 0xAA;

    [Fact]
    public static void Parse_tpms_attest_with_valid_data_returns_expected_values()
    {
        var qualifiedSigner = new byte[] { 1, 2 };
        var extraData = new byte[] { 3, 4, 5 };
        var name = new byte[] { 6, 7, 8 };
        var qualifiedName = new byte[] { 9, 10 };
        var clock = TestClock;
        var resetCount = TestResetCount;
        var restartCount = TestRestartCount;
        var safe = TestSafe;
        var firmwareVersion = TestFirmwareVersion;
        var bytes = CreateTpmsAttestBytes(
            TpmConstants.GeneratedValue,
            TpmConstants.StAttestCertify,
            qualifiedSigner,
            extraData,
            clock,
            resetCount,
            restartCount,
            safe,
            firmwareVersion,
            name,
            qualifiedName);

        var result = TpmsAttest.Parse(bytes);

        result.Magic.ShouldBe(TpmConstants.GeneratedValue);
        result.Type.ShouldBe(TpmConstants.StAttestCertify);
        result.QualifiedSigner.ShouldBe(qualifiedSigner);
        result.ExtraData.ShouldBe(extraData);
        result.ClockInfo.Clock.ShouldBe(clock);
        result.ClockInfo.ResetCount.ShouldBe(resetCount);
        result.ClockInfo.RestartCount.ShouldBe(restartCount);
        result.ClockInfo.Safe.ShouldBe(safe);
        result.FirmwareVersion.ShouldBe(firmwareVersion);
        result.Attested.Name.ShouldBe(name);
        result.Attested.QualifiedName.ShouldBe(qualifiedName);
    }

