    [Fact]
    public static void Parse_tpmt_public_with_valid_Rsa_data_returns_expected_values()
    {
        var authPolicy = new byte[] { 1, 2 };
        var modulus = new byte[] { 3, 4, 5, 6 };
        var objectAttributes = TestObjectAttributes;
        var keyBits = TestRsaKeyBits;
        var exponent = TestRsaExponent;
        var bytes = CreateRsaTpmtPublicBytes(
            TpmConstants.AlgSha256,
            objectAttributes,
            authPolicy,
            TpmConstants.AlgNull,
            TpmConstants.AlgNull,
            keyBits,
            exponent,
            modulus);

        var result = TpmtPublic.Parse(bytes);

        result.Type.ShouldBe(TpmConstants.AlgRsa);
        result.NameAlg.ShouldBe(TpmConstants.AlgSha256);
        result.ObjectAttributes.ShouldBe(objectAttributes);
        result.AuthPolicy.ShouldBe(authPolicy);
        result.Parameters.ShouldBe(CreateRsaParametersBytes(TpmConstants.AlgNull, TpmConstants.AlgNull, keyBits,
            exponent));
        _ = result.RsaParameters.ShouldNotBeNull();
        result.RsaParameters.Symmetric.ShouldBe(TpmConstants.AlgNull);
        result.RsaParameters.Scheme.ShouldBe(TpmConstants.AlgNull);
        result.RsaParameters.KeyBits.ShouldBe(keyBits);
        result.RsaParameters.Exponent.ShouldBe(exponent);
        result.Unique.RsaModulus.ShouldBe(modulus);
        result.Unique.EccX.ShouldBeNull();
        result.Unique.EccY.ShouldBeNull();
        result.EccParameters.ShouldBeNull();
    }

    [Fact]
    public static void Parse_tpmt_public_with_valid_Ecc_data_returns_expected_values()
    {
        var authPolicy = new byte[] { 1, 2 };
        var x = new byte[] { 3, 4, 5 };
        var y = new byte[] { 6, 7, 8 };
        var objectAttributes = AlternateTestObjectAttributes;
        var curveId = TpmConstants.EccCurveNistP256;
        var kdf = NullKdf;
        var bytes = CreateEccTpmtPublicBytes(
            TpmConstants.AlgSha256,
            objectAttributes,
            authPolicy,
            TpmConstants.AlgNull,
            TpmConstants.AlgNull,
            curveId,
            kdf,
            x,
            y);

        var result = TpmtPublic.Parse(bytes);

        result.Type.ShouldBe(TpmConstants.AlgEcc);
        result.NameAlg.ShouldBe(TpmConstants.AlgSha256);
        result.ObjectAttributes.ShouldBe(objectAttributes);
        result.AuthPolicy.ShouldBe(authPolicy);
        result.Parameters.ShouldBe(CreateEccParametersBytes(TpmConstants.AlgNull, TpmConstants.AlgNull, curveId, kdf));
        _ = result.EccParameters.ShouldNotBeNull();
        result.EccParameters.Symmetric.ShouldBe(TpmConstants.AlgNull);
        result.EccParameters.Scheme.ShouldBe(TpmConstants.AlgNull);
        result.EccParameters.CurveId.ShouldBe(curveId);
        result.EccParameters.Kdf.ShouldBe(kdf);
        result.Unique.RsaModulus.ShouldBeNull();
        result.Unique.EccX.ShouldBe(x);
        result.Unique.EccY.ShouldBe(y);
        result.RsaParameters.ShouldBeNull();
    }

