    [Fact]
    public static void Parse_tpmt_public_with_non_null_rsa_symmetric_throws_format_exception()
    {
        var arbitraryAuthPolicy = new byte[] { 1 };
        var arbitraryModulus = new byte[] { 2, 3, 4, 5 };
        var bytes = CreateRsaTpmtPublicBytes(
            TpmConstants.AlgSha256,
            TestObjectAttributes,
            arbitraryAuthPolicy,
            UnsupportedAlgorithmId,
            TpmConstants.AlgNull,
            TestRsaKeyBits,
            TestRsaExponent,
            arbitraryModulus);

        var exception = Should.Throw<FormatException>(() => TpmtPublic.Parse(bytes));

        ShouldlyExtensions.ShouldContain(exception.Message, "TPMS_RSA_PARMS Symmetric");
        ShouldlyExtensions.ShouldContain(exception.Message, "TPM_ALG_NULL");
    }

