    }

    [Fact]
    public static void Compute_name_with_Sha256_name_alg_returns_algorithm_prefix_and_Sha256_digest()
    {
        var objectAttributes = TestObjectAttributes;
        var authPolicy = new byte[] { 1, 2 };
        var modulus = new byte[] { 3, 4, 5, 6 };
        var pubAreaBytes = CreateRsaTpmtPublicBytes(
            TpmConstants.AlgSha256,
            objectAttributes,
            authPolicy,
            TpmConstants.AlgNull,
            TpmConstants.AlgNull,
            TestRsaKeyBits,
            TestRsaExponent,
            modulus);
        var pubArea = TpmtPublic.Parse(pubAreaBytes);
        var expectedDigest = SHA256.HashData(pubAreaBytes);
        var expectedName = new byte[sizeof(ushort) + expectedDigest.Length];
        BinaryPrimitives.WriteUInt16BigEndian(expectedName.AsSpan(), TpmConstants.AlgSha256);
        expectedDigest.CopyTo(expectedName.AsSpan(sizeof(ushort)));

        var result = pubArea.ComputeName(pubAreaBytes);

        result.ShouldBe(expectedName);
    }

