    [Fact]
    public static void Validate_public_key_match_for_Rsa_when_modulus_and_exponent_match_returns_true()
    {
        var modulus = new byte[] { 1, 2, 3, 4 };
        var exponent = new byte[] { 0x01, 0x00, 0x01 }; // 65537 in big-endian
        var authPolicy = new byte[] { 5, 6 };
        var pubArea = TpmtPublic.Parse(CreateRsaTpmtPublicBytes(
            TpmConstants.AlgSha256,
            TestObjectAttributes,
            authPolicy,
            TpmConstants.AlgNull,
            TpmConstants.AlgNull,
            TestRsaKeyBits,
            TestRsaExponent,
            modulus));
        var credentialPublicKey = CreateRsaCoseKey(modulus, exponent);

        var result = TpmStructures.ValidatePublicKeyMatch(pubArea, credentialPublicKey);

        result.ShouldBeTrue();
    }

