    private static TpmsAttest CreateTpmsAttest(byte[] extraData, byte[] attestedName) =>
        new(
            TpmConstants.GeneratedValue,
            TpmConstants.StAttestCertify,
            [],
            extraData,
            new TpmsClockInfo(0, 0, 0, 0),
            0,
            new TpmsCertifyInfo(attestedName, []));

    private static CoseKey CreateRsaCoseKey(byte[] modulus, byte[] exponent)
    {
        var writer = new CborWriter();
        writer.WriteStartMap(4);
        writer.WriteInt32(CoseConstants.Labels.KeyType);
        writer.WriteInt32(CoseConstants.KeyTypes.Rsa);
        writer.WriteInt32(CoseConstants.Labels.Algorithm);
        writer.WriteInt32(CoseAlgorithms.Rs256);
        writer.WriteInt32(CoseConstants.Labels.RsaModulus);
        writer.WriteByteString(modulus);
        writer.WriteInt32(CoseConstants.Labels.RsaExponent);
        writer.WriteByteString(exponent);
        writer.WriteEndMap();
        var cbor = writer.Encode();
        _ = CoseKey.TryParse(cbor, out var key);
        return key!;
    }

    private static CoseKey CreateEccCoseKey(int curve, byte[] x, byte[] y)
    {
        var writer = new CborWriter();
        writer.WriteStartMap(5);
        writer.WriteInt32(CoseConstants.Labels.KeyType);
        writer.WriteInt32(CoseConstants.KeyTypes.Ec2);
        writer.WriteInt32(CoseConstants.Labels.Algorithm);
        writer.WriteInt32(CoseAlgorithms.Es256);
        writer.WriteInt32(CoseConstants.Labels.EcCurve);
        writer.WriteInt32(curve);
        writer.WriteInt32(CoseConstants.Labels.EcX);
        writer.WriteByteString(x);
        writer.WriteInt32(CoseConstants.Labels.EcY);
        writer.WriteByteString(y);
        writer.WriteEndMap();
        var cbor = writer.Encode();
        _ = CoseKey.TryParse(cbor, out var key);
        return key!;
    }

    private static byte[] CreateTpmsAttestBytes(
        uint magic,
        ushort type,
        byte[] qualifiedSigner,
        byte[] extraData,
        ulong clock,
        uint resetCount,
        uint restartCount,
        byte safe,
        ulong firmwareVersion,
        byte[] name,
        byte[] qualifiedName)
    {
        var buffer = new List<byte>();
        AddUInt32(buffer, magic);
        AddUInt16(buffer, type);
        AddTpm2B(buffer, qualifiedSigner);
        AddTpm2B(buffer, extraData);
        AddUInt64(buffer, clock);
        AddUInt32(buffer, resetCount);
        AddUInt32(buffer, restartCount);
        buffer.Add(safe);
        AddUInt64(buffer, firmwareVersion);
        AddTpm2B(buffer, name);
        AddTpm2B(buffer, qualifiedName);
        return [.. buffer];
    }

    private static byte[] CreateRsaTpmtPublicBytes(
        ushort nameAlg,
        uint objectAttributes,
        byte[] authPolicy,
        ushort symmetric,
        ushort scheme,
        ushort keyBits,
        uint exponent,
        byte[] modulus)
    {
        var buffer = new List<byte>();
        AddUInt16(buffer, TpmConstants.AlgRsa);
        AddUInt16(buffer, nameAlg);
        AddUInt32(buffer, objectAttributes);
        AddTpm2B(buffer, authPolicy);
        AddBytes(buffer, CreateRsaParametersBytes(symmetric, scheme, keyBits, exponent));
        AddTpm2B(buffer, modulus);
        return [.. buffer];
    }

    private static byte[] CreateEccTpmtPublicBytes(
        ushort nameAlg,
        uint objectAttributes,
        byte[] authPolicy,
        ushort symmetric,
        ushort scheme,
        ushort curveId,
        ushort kdf,
        byte[] x,
        byte[] y)
    {
        var buffer = new List<byte>();
        AddUInt16(buffer, TpmConstants.AlgEcc);
        AddUInt16(buffer, nameAlg);
        AddUInt32(buffer, objectAttributes);
        AddTpm2B(buffer, authPolicy);
        AddBytes(buffer, CreateEccParametersBytes(symmetric, scheme, curveId, kdf));
        AddTpm2B(buffer, x);
        AddTpm2B(buffer, y);
        return [.. buffer];
    }

    private static byte[] CreateRsaParametersBytes(ushort symmetric, ushort scheme, ushort keyBits, uint exponent)
    {
        var buffer = new List<byte>();
        AddUInt16(buffer, symmetric);
        AddUInt16(buffer, scheme);
        AddUInt16(buffer, keyBits);
        AddUInt32(buffer, exponent);
        return [.. buffer];
    }

    private static byte[] CreateEccParametersBytes(ushort symmetric, ushort scheme, ushort curveId, ushort kdf)
    {
        var buffer = new List<byte>();
        AddUInt16(buffer, symmetric);
        AddUInt16(buffer, scheme);
        AddUInt16(buffer, curveId);
        AddUInt16(buffer, kdf);
        return [.. buffer];
    }

    private static byte[] CreateUInt16Bytes(ushort value)
    {
        var bytes = new byte[sizeof(ushort)];
        BinaryPrimitives.WriteUInt16BigEndian(bytes, value);
        return bytes;
    }

    private static byte[] Combine(byte[] first, byte[] second)
    {
        var combined = new byte[first.Length + second.Length];
        first.CopyTo(combined, 0);
        second.CopyTo(combined, first.Length);
        return combined;
    }

    private static void AddTpm2B(List<byte> buffer, byte[] value)
    {
        AddUInt16(buffer, (ushort)value.Length);
        AddBytes(buffer, value);
    }

    private static void AddUInt16(List<byte> buffer, ushort value)
    {
        var bytes = new byte[sizeof(ushort)];
        BinaryPrimitives.WriteUInt16BigEndian(bytes, value);
        AddBytes(buffer, bytes);
    }

    private static void AddUInt32(List<byte> buffer, uint value)
    {
        var bytes = new byte[sizeof(uint)];
        BinaryPrimitives.WriteUInt32BigEndian(bytes, value);
        AddBytes(buffer, bytes);
    }

    private static void AddUInt64(List<byte> buffer, ulong value)
    {
        var bytes = new byte[sizeof(ulong)];
        BinaryPrimitives.WriteUInt64BigEndian(bytes, value);
        AddBytes(buffer, bytes);
    }

    private static void AddBytes(List<byte> buffer, byte[] bytes) => buffer.AddRange(bytes);
}
